#include <stdio.h>
#include <math.h>

// Approximation for t-distribution critical values
double t_critical_approx(double alpha, int df) {
    // Using approximation formula for two-tailed test
    double z = 1.96; // Approx for alpha = 0.05

    if (alpha == 0.05) {
        z = 1.96;
    } else if (alpha == 0.01) {
        z = 2.576;
    } else if (alpha == 0.10) {
        z = 1.645;
    }

    // Adjustment factor for small samples
    double adjustment = 1.0 + (1.0 / (4.0 * df));
    return z * adjustment;
}

// Calculate t-statistic for one-sample test
double calculate_t_statistic(double sample_mean, double pop_mean, 
                              double sample_std, int n) {
    double standard_error = sample_std / sqrt((double)n);
    return (sample_mean - pop_mean) / standard_error;
}

int main() {
    // Example: Sample of 15 students
    double sample_mean = 78.0;
    double pop_mean = 72.0;
    double sample_std = 8.0;
    int n = 15;

    double t_stat = calculate_t_statistic(sample_mean, pop_mean, sample_std, n);
    double t_crit = t_critical_approx(0.05, n - 1);

    printf("Sample size: %d\n", n);
    printf("Sample mean: %.2f\n", sample_mean);
    printf("Population mean: %.2f\n", pop_mean);
    printf("t-statistic: %.4f\n", t_stat);
    printf("Critical t (alpha=0.05, df=%d): %.4f\n", n-1, t_crit);

    if (fabs(t_stat) > t_crit) {
        printf("Result: Reject null hypothesis\n");
    } else {
        printf("Result: Fail to reject null hypothesis\n");
    }

    return 0;
}
